#!/usr/bin/env node
// Generate the tracked ge.manifest.schema.json (JSON Schema draft-07) for
// ge.manifest.json — the desired-state file `ge apply`/`ge apply --plan`
// reads (tools/lib/apply-ops.mjs, tools/lib/reconcile.mjs). .ge.json already
// gets this treatment (.ge.schema.json, generated by gen-config-schema.mjs
// from CONFIG_FIELDS); ge.manifest.json had the identical gap — no schema
// file anywhere, so an editor gives no autocomplete/validation on it, and a
// typo'd key silently no-ops instead of erroring (reconcile.mjs's
// normalizeManifest() only ever reads known keys with `|| default`).
//
// The shape below is read directly off reconcile.mjs's normalizeManifest()
// and planReconcile() (platform.{infra,data,mcp} booleans; fleet.mode
// local|remote; fleet.target one of run-ledger's LEDGER_STAGES; fleet.agents
// "all" or an array of agent ids) — no invented fields.
//
//   node tools/gen-manifest-schema.mjs           # regenerate ge.manifest.schema.json
//   node tools/gen-manifest-schema.mjs --check   # exit 1 on drift, with a diff
import { readFileSync, writeFileSync } from "node:fs";
import { dirname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import { LEDGER_STAGES } from "../packages/run-ledger/src/store.mjs";

const HERE = dirname(fileURLToPath(import.meta.url));
const ROOT = join(HERE, "..");

export const SCHEMA_REL_PATH = "ge.manifest.schema.json";

// Build the schema object (deterministic — no generated-from-a-loop
// nondeterminism to worry about, but kept as a pure function like
// gen-config-schema.mjs's buildSchema for the same testability reason).
export function buildSchema() {
  return {
    $schema: "http://json-schema.org/draft-07/schema#",
    title: "ge.manifest.json — ge apply desired state",
    description:
      "Generated from tools/lib/reconcile.mjs's normalizeManifest()/planReconcile() by tools/gen-manifest-schema.mjs — do not edit; run `bun run manifest:schema`. `ge apply` diffs this against actual platform/fleet state and plans the drift in dependency order (gateway -> data -> tool plane -> agents); `ge apply --yes` executes it.",
    type: "object",
    additionalProperties: false,
    properties: {
      $schema: {
        type: "string",
        description: "Reference to this schema (e.g. ./ge.manifest.schema.json).",
      },
      _comment: {
        type: "string",
        description: "Free-text note for humans reading the manifest — ignored by ge apply.",
      },
      platform: {
        type: "object",
        description: "Platform planes to bring up, opt-in — declare what must be up before the fleet is provisioned.",
        additionalProperties: false,
        properties: {
          infra: { type: "boolean", description: "Factory/runtime plane (ge up --infra)." },
          data: { type: "boolean", description: "Data plane: shared stores (ge data up)." },
          mcp: { type: "boolean", description: "Tool plane: per-department MCP services (ge mcp deploy)." },
        },
      },
      fleet: {
        type: "object",
        description: "Target stage and which agents to converge on it.",
        additionalProperties: false,
        properties: {
          mode: {
            type: "string",
            enum: ["local", "remote"],
            default: "local",
            description: "Build locally via the harness, or submit to the cloud factory.",
          },
          target: {
            type: "string",
            enum: LEDGER_STAGES,
            default: "previewed",
            description: "Stage every selected agent should converge to (run-ledger's LEDGER_STAGES).",
          },
          agents: {
            description: "\"all\" (every agent in the catalog), or an explicit list of agent ids.",
            default: "all",
            oneOf: [{ type: "string", enum: ["all"] }, { type: "array", items: { type: "string" } }],
          },
        },
      },
    },
  };
}

// Render the exact bytes of the tracked file.
export function renderSchema() {
  return JSON.stringify(buildSchema(), null, 2) + "\n";
}

// Byte-compare the tracked ge.manifest.schema.json against the rendered
// truth. Returns findings instead of printing (rendering happens at the CLI
// boundary below).
export function checkSchema(root = ROOT) {
  const expected = renderSchema();
  let actual;
  try {
    actual = readFileSync(join(root, SCHEMA_REL_PATH), "utf8");
  } catch {
    return { ok: false, findings: [{ file: SCHEMA_REL_PATH, actual: "", expected, missing: true }] };
  }
  if (actual === expected) return { ok: true, findings: [] };
  return { ok: false, findings: [{ file: SCHEMA_REL_PATH, actual, expected }] };
}

// Rewrite the tracked file in place. Returns the list of files whose bytes
// actually changed.
export function writeSchema(root = ROOT) {
  const expected = renderSchema();
  const path = join(root, SCHEMA_REL_PATH);
  let actual;
  try {
    actual = readFileSync(path, "utf8");
  } catch {
    actual = null;
  }
  if (actual === expected) return { changed: [] };
  writeFileSync(path, expected);
  return { changed: [SCHEMA_REL_PATH] };
}

export function formatCheckReport(result) {
  if (result.ok) {
    return `Manifest schema check passed: ${SCHEMA_REL_PATH} matches reconcile.mjs's manifest shape.`;
  }
  const lines = [`Manifest schema check failed: ${SCHEMA_REL_PATH} drifted from reconcile.mjs's manifest shape.`];
  for (const finding of result.findings) {
    if (finding.missing) {
      lines.push("", `${finding.file} is missing — run: bun run manifest:schema`);
      continue;
    }
    lines.push("", `--- ${finding.file} (on disk)`, `+++ ${finding.file} (generated from tools/lib/reconcile.mjs)`);
    const actualLines = finding.actual.split("\n");
    const expectedLines = finding.expected.split("\n");
    for (let i = 0; i < Math.max(actualLines.length, expectedLines.length); i += 1) {
      if (actualLines[i] !== expectedLines[i]) {
        if (actualLines[i] !== undefined) lines.push(`-${actualLines[i]}`);
        if (expectedLines[i] !== undefined) lines.push(`+${expectedLines[i]}`);
      }
    }
  }
  lines.push("", "Edit tools/gen-manifest-schema.mjs's buildSchema() to match reconcile.mjs, then run: bun run manifest:schema");
  return lines.join("\n");
}

// Run only when this file is the process entry point (house pattern from
// apps/factory/scripts/factory.mjs) — importing it must stay side-effect-free.
const __isEntryPoint = (() => {
  try {
    const invoked = process.argv?.[1] ? new URL(`file://${resolve(process.argv[1])}`).href : null;
    return invoked === import.meta.url;
  } catch {
    return false;
  }
})();

if (__isEntryPoint) {
  try {
    if (process.argv.includes("--check")) {
      const result = checkSchema();
      const writer = result.ok ? process.stdout : process.stderr;
      writer.write(formatCheckReport(result) + "\n");
      process.exit(result.ok ? 0 : 1);
    } else {
      const { changed } = writeSchema();
      for (const file of changed) console.log(`generated ${file}`);
      if (!changed.length) console.log(`${SCHEMA_REL_PATH} already up to date`);
    }
  } catch (e) {
    console.error(e.message);
    process.exit(1);
  }
}
